package com.hospital.management.model;import java.math.*;import java.time.*;/** Physical bed; occupancy is controlled only by admission transactions. */public class Bed{private Long bedId,roomId,currentAdmissionId,currentPatientId;private String roomNumber,roomType,bedNumber,status,currentPatientName;private BigDecimal dailyRate;private LocalDateTime createdAt,updatedAt;public Long getBedId(){return bedId;}public void setBedId(Long v){bedId=v;}public Long getRoomId(){return roomId;}public void setRoomId(Long v){roomId=v;}public String getRoomNumber(){return roomNumber;}public void setRoomNumber(String v){roomNumber=v;}public String getRoomType(){return roomType;}public void setRoomType(String v){roomType=v;}public String getBedNumber(){return bedNumber;}public void setBedNumber(String v){bedNumber=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public BigDecimal getDailyRate(){return dailyRate;}public void setDailyRate(BigDecimal v){dailyRate=v;}public Long getCurrentAdmissionId(){return currentAdmissionId;}public void setCurrentAdmissionId(Long v){currentAdmissionId=v;}public Long getCurrentPatientId(){return currentPatientId;}public void setCurrentPatientId(Long v){currentPatientId=v;}public String getCurrentPatientName(){return currentPatientName;}public void setCurrentPatientName(String v){currentPatientName=v;}public LocalDateTime getCreatedAt(){return createdAt;}public void setCreatedAt(LocalDateTime v){createdAt=v;}public LocalDateTime getUpdatedAt(){return updatedAt;}public void setUpdatedAt(LocalDateTime v){updatedAt=v;}}
